from order_domain import Money, Order, OrderStatus


def payable_total(order: Order, tax_rate: float) -> Money:
    if order.status is OrderStatus.CANCELLED:
        raise ValueError("cancelled order")
    if tax_rate < 0:
        raise ValueError("negative tax")
    subtotal = sum(line.unit_price.amount * line.quantity for line in order.lines)
    currency = order.lines[0].unit_price.currency if order.lines else order.currency
    if any(line.unit_price.currency != currency for line in order.lines):
        raise ValueError("mixed currencies")
    return Money(round(subtotal * (1 + tax_rate), 2), currency)

