from access_domain import Permission, User


def can_access(user: User, permission: Permission, owner_id: str | None = None) -> bool:
    if user.suspended:
        return False
    if any(permission in role.grants for role in user.roles):
        return True
    return permission is Permission.EDIT_OWN and owner_id == user.user_id

