from payment_ports import PaymentDeclined, PaymentGateway, PaymentRequest, PaymentResult


def collect_payment(gateway: PaymentGateway, order_id: str, cents: int, token: str) -> PaymentResult:
    if cents <= 0:
        raise ValueError("amount must be positive")
    response = gateway.charge(PaymentRequest(order_id, cents, token))
    if not response.approved:
        raise PaymentDeclined(response.reason or "declined")
    return PaymentResult(order_id, response.transaction_id, cents)

