from catalog_ports import CachePort, Product, ProductRepository


class CatalogService:
    def __init__(self, repository: ProductRepository, cache: CachePort) -> None:
        self.repository = repository
        self.cache = cache

    def find(self, sku: str) -> Product | None:
        cached = self.cache.read(f"product:{sku}")
        if cached is not None:
            return Product.from_mapping(cached)
        product = self.repository.find_by_sku(sku)
        if product is not None:
            self.cache.write(f"product:{sku}", product.to_mapping(), ttl_seconds=60)
        return product

