from notification_ports import Delivery, MailClient, MailMessage, Recipient


def send_welcome(client: MailClient, recipient: Recipient) -> Delivery:
    if not recipient.email or "@" not in recipient.email:
        raise ValueError("invalid recipient")
    message = MailMessage(to=(recipient.email,), subject="Welcome", text=f"Hello {recipient.display_name}!")
    receipt = client.deliver(message)
    return Delivery(recipient.identifier, receipt.message_id, receipt.accepted)

