def parse_environment(values: Mapping[str, str]) -> DeploymentSettings:
    host = values.get("APP_HOST", "127.0.0.1").strip()
    port = int(values.get("APP_PORT", str(DEFAULT_PORT)))
    if not 1 <= port <= 65535:
        raise ValueError("invalid port")
    debug = values.get("APP_DEBUG", "false").lower() in {"1", "true", "yes"}
    level = LogLevel(values.get("APP_LOG_LEVEL", "info").lower())
    return DeploymentSettings(host, port, debug, level)

from collections import defaultdict, deque

from rate_contracts import Clock, RateLimitDecision, RateLimitPolicy


class WindowRateLimiter:
    def __init__(self, policy: RateLimitPolicy, clock: Clock) -> None:
        self.policy = policy
        self.clock = clock
        self._events: dict[str, deque[float]] = defaultdict(deque)

    def check(self, key: str) -> RateLimitDecision:
        now = self.clock.monotonic()
        events = self._events[key]
        cutoff = now - self.policy.window_seconds
        while events and events[0] <= cutoff:
            events.popleft()
        if len(events) >= self.policy.max_requests:
            return RateLimitDecision(False, 0, events[0] + self.policy.window_seconds)
        events.append(now)
        return RateLimitDecision(True, self.policy.max_requests - len(events), None)

