from typing import Generic, TypeVar

from cache_contracts import CacheEntry, TimeProvider


T = TypeVar("T")


class ExpiringCache(Generic[T]):
    def __init__(self, time_provider: TimeProvider) -> None:
        self.time_provider = time_provider
        self._values: dict[str, CacheEntry[T]] = {}

    def put(self, key: str, value: T, ttl_seconds: float) -> None:
        if ttl_seconds <= 0:
            raise ValueError("ttl must be positive")
        self._values[key] = CacheEntry(value, self.time_provider.now() + ttl_seconds)

    def get(self, key: str) -> T | None:
        entry = self._values.get(key)
        if entry is None:
            return None
        if entry.expires_at <= self.time_provider.now():
            del self._values[key]
            return None
        return entry.value

