from inventory_domain import InsufficientStock, Reservation, StockItem


class InventoryService:
    def __init__(self, items: list[StockItem]) -> None:
        self._items = {item.sku: item for item in items}
        self._reservations: dict[str, Reservation] = {}

    def reserve(self, reservation_id: str, sku: str, quantity: int) -> Reservation:
        if quantity <= 0:
            raise ValueError("quantity must be positive")
        if reservation_id in self._reservations:
            return self._reservations[reservation_id]
        item = self._items.get(sku)
        if item is None or item.available < quantity:
            raise InsufficientStock(sku)
        item.available -= quantity
        reservation = Reservation(reservation_id, sku, quantity)
        self._reservations[reservation_id] = reservation
        return reservation

    def release(self, reservation_id: str) -> bool:
        reservation = self._reservations.pop(reservation_id, None)
        if reservation is None:
            return False
        self._items[reservation.sku].available += reservation.quantity
        return True

