from resource_contracts import QueryLease, ResourcePool


class ManagedQuery:
    def __init__(self, pool: ResourcePool, statement: str) -> None:
        self.pool = pool
        self.statement = statement
        self.lease: QueryLease | None = None

    def __enter__(self) -> list[dict[str, object]]:
        self.lease = self.pool.acquire()
        return self.lease.connection.query(self.statement)

    def __exit__(self, exc_type, exc, traceback) -> bool:
        assert self.lease is not None
        self.pool.release(self.lease, broken=exc is not None)
        return False

