from collections.abc import Callable
from typing import TypeVar

from retry_contracts import RetryExhausted, RetryPolicy, Sleeper


T = TypeVar("T")


def execute_with_retry(operation: Callable[[], T], policy: RetryPolicy, sleeper: Sleeper) -> T:
    last_error: Exception | None = None
    for attempt in range(1, policy.max_attempts + 1):
        try:
            return operation()
        except policy.retryable_exceptions as error:
            last_error = error
            if attempt < policy.max_attempts:
                sleeper.sleep(policy.delay_for(attempt))
    raise RetryExhausted(policy.max_attempts, last_error)

