import pytest
from retry_contracts import RetryExhausted, RetryPolicy
from retry_executor import execute_with_retry


class Sleeper:
    def __init__(self): self.delays = []
    def sleep(self, seconds): self.delays.append(seconds)


def test_retries_with_policy_backoff():
    calls = []
    def operation():
        calls.append(1)
        if len(calls) < 3: raise RuntimeError("temporary")
        return "ok"
    sleeper = Sleeper()
    assert execute_with_retry(operation, RetryPolicy(3, 0.5), sleeper) == "ok"
    assert sleeper.delays == [0.5, 1.0]


def test_non_retryable_propagates_and_exhaustion_wraps():
    with pytest.raises(ValueError): execute_with_retry(lambda: (_ for _ in ()).throw(ValueError("bad")), RetryPolicy(2, 1), Sleeper())
    with pytest.raises(RetryExhausted) as caught:
        execute_with_retry(lambda: (_ for _ in ()).throw(RuntimeError("bad")), RetryPolicy(2, 1), Sleeper())
    assert caught.value.attempts == 2 and isinstance(caught.value.last_error, RuntimeError)
